export function prefixSchemaToErrors(
  zodErrors: ZodIssue[],
  transformErrors: TransformFn,
) {
  const schema = new Map<string, ZodIssue[]>()

  for (const zodError of zodErrors) {
    const path = zodError.path
      .map((segment) =>
        typeof segment === 'number' ? `[${segment}]` : segment,
