  return (
    <div className="form-container">
      <h1>Registration</h1>

      <div className="step-indicator">
        <span className={`step ${step === 1 ? 'active' : ''}`}>
          Step 1: User Info
        </span>
        <span className="step-divider" />
        <span className={`step ${step === 2 ? 'active' : ''}`}>
          Step 2: Account Info
        </span>
