                </div>
              )}
            </form.Field>

            <div className="button-group">
              <button
                type="button"
                className="btn btn-primary"
                onClick={handleNext}
              >
                Next
              </button>
            </div>
          </div>
        )}

        {step === 2 && (
          <div className="step-content">
