.form-container {
  max-width: 480px;
  margin: 60px auto;
  padding: 32px;
  text-align: left;
}

.form-container h1 {
  text-align: center;
  margin-bottom: 24px;
}

.step-indicator {
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 12px;
  margin-bottom: 32px;
  font-size: 14px;
}

.step {
  color: var(--text);
  opacity: 0.5;
  transition: opacity 0.2s;
}

.step.active {
  opacity: 1;
  color: var(--accent);
  font-weight: 600;
}

.step-divider {
  width: 40px;
  height: 1px;
  background: var(--border);
}

.step-content {
  display: flex;
  flex-direction: column;
  gap: 20px;
}

.field {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.field label {
  font-size: 14px;
  font-weight: 500;
  color: var(--text-h);
}

.field input {
  padding: 10px 12px;
  border: 1px solid var(--border);
  border-radius: 6px;
  font-size: 16px;
  font-family: inherit;
  color: var(--text-h);
  background: var(--bg);
  transition: border-color 0.2s;
  outline: none;
}

.field input:focus {
  border-color: var(--accent);
  box-shadow: 0 0 0 2px var(--accent-bg);
}

.field .error {
  font-size: 13px;
  color: #ef4444;
}

.button-group {
  display: flex;
  gap: 12px;
  margin-top: 8px;
}

.button-group:has(> :only-child) {
  justify-content: flex-end;
}

.btn {
  padding: 10px 24px;
  border: none;
  border-radius: 6px;
  font-size: 16px;
  font-family: inherit;
  cursor: pointer;
  transition: background 0.2s, box-shadow 0.2s;
}

.btn-primary {
  background: var(--accent);
  color: #fff;
}

.btn-primary:hover {
  box-shadow: 0 0 0 2px var(--accent-border);
}

